import sqlite3
import hashlib
import os
from typing import Optional, Dict, Any


def init_database(db_path: str = "legacy_users.db") -> sqlite3.Connection:
    """Initialize the legacy database with a users table if it doesn't exist."""
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username VARCHAR(255) UNIQUE NOT NULL,
            password_hash VARCHAR(255) NOT NULL,
            salt VARCHAR(255) NOT NULL,
            display_name VARCHAR(255),
            email VARCHAR(255),
            is_active INTEGER DEFAULT 1,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            last_login TIMESTAMP
        )
    """)
    conn.commit()
    return conn


def _hash_password(password: str, salt: str) -> str:
    """Hash a password with the given salt using SHA-256 (legacy compatible)."""
    salted = salt + password
    return hashlib.sha256(salted.encode("utf-8")).hexdigest()


def register_user(
    conn: sqlite3.Connection,
    username: str,
    password: str,
    display_name: str = "",
    email: str = "",
) -> bool:
    """Register a new user in the legacy database."""
    try:
        salt = os.urandom(16).hex()
        password_hash = _hash_password(password, salt)
        cursor = conn.cursor()
        cursor.execute(
            """
            INSERT INTO users (username, password_hash, salt, display_name, email)
            VALUES (?, ?, ?, ?, ?)
            """,
            (username, password_hash, salt, display_name, email),
        )
        conn.commit()
        print(f"User '{username}' registered successfully.")
        return True
    except sqlite3.IntegrityError:
        print(f"Error: Username '{username}' already exists.")
        return False
    except sqlite3.Error as e:
        print(f"Database error during registration: {e}")
        return False


def login(
    conn: sqlite3.Connection, username: str, password: str
) -> Optional[Dict[str, Any]]:
    """
    Authenticate a user by checking the provided username and password
    against the users table in the legacy database.

    Returns user info dict on success, None on failure.
    """
    try:
        cursor = conn.cursor()

        # Query the legacy users table for the given username
        cursor.execute(
            """
            SELECT id, username, password_hash, salt, display_name, email, is_active
            FROM users
            WHERE username = ?
            """,
            (username,),
        )

        row = cursor.fetchone()

        if row is None:
            print("Login failed: Invalid username or password.")
            return None

        # Check if account is active (legacy systems often have soft deletes)
        if not row["is_active"]:
            print("Login failed: Account is deactivated.")
            return None

        # Verify password against stored hash
        stored_hash = row["password_hash"]
        salt = row["salt"]
        computed_hash = _hash_password(password, salt)

        if computed_hash != stored_hash:
            print("Login failed: Invalid username or password.")
            return None

        # Update last_login timestamp (legacy audit trail)
        cursor.execute(
            """
            UPDATE users SET last_login = CURRENT_TIMESTAMP WHERE id = ?
            """,
            (row["id"],),
        )
        conn.commit()

        user_info = {
            "id": row["id"],
            "username": row["username"],
            "display_name": row["display_name"],
            "email": row["email"],
        }

        print(f"Login successful. Welcome, {user_info['display_name'] or user_info['username']}!")
        return user_info

    except sqlite3.Error as e:
        print(f"Database error during login: {e}")
        return None


def deactivate_user(conn: sqlite3.Connection, username: str) -> bool:
    """Deactivate a user account (legacy soft delete)."""
    try:
        cursor = conn.cursor()
        cursor.execute(
            "UPDATE users SET is_active = 0 WHERE username = ?", (username,)
        )
        conn.commit()
        return cursor.rowcount > 0
    except sqlite3.Error as e:
        print(f"Database error: {e}")
        return False


